class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        vector<int> result;
        for (int i = 0; i < 20; ++i) {
            long long xi = pow(x, i);
            if (xi > bound) break;
            for (int j = 0; j < 20; ++j) {
                long long yj = pow(y, j);
                long long sum = xi + yj;
                if (sum > bound) break;
                result.push_back(sum);
            }
        }
        sort(result.begin(), result.end());
        result.erase(unique(result.begin(), result.end()), result.end());
        return result;
    }
};
```
